// 核心 RAG 串接與 Stream 讀取實作片段
async function handleAIRAGFlow(question, searchResults, loadingBubble) {
  const relevantResults = searchResults.slice(0, 3);
  const contextText = relevantResults.map((r, idx) => {
    const doc = allDocuments.find(d => d.id === r.id);
    return `【資料來源 ${idx + 1}】\n標題: ${doc.title}\n內容: ${doc.content}`;
  }).join('\n\n');

  const response = await fetch(CONFIG.workerUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ question, context: contextText })
  });

  removeLoading(loadingBubble);
  const botMsgBubble = appendMessage('', 'bot');
  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let done = false, accumulatedText = '';

  while (!done) {
    const { value, done: readerDone } = await reader.read();
    done = readerDone;
    if (value) {
      accumulatedText += decoder.decode(value, { stream: true });
      botMsgBubble.innerHTML = accumulatedText.replace(/\n/g, '<br>').replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
    }
  }
}

// Express BFF 控制器：安全過濾並綁定個人 Telegram Chat ID
const express = require('express');
const router = express.Router();
const { User } = require('../models'); // Sequelize 使用者模型

router.post('/api/user/telegram-bind', async (req, res) => {
  try {
    const { telegramChatId } = req.body;

    // 1. 欄位格式校驗：限制格式為數字，防止 SQL 注入與非法輸入
    const chatIdRegex = /^-?\d+$/;
    if (!telegramChatId || !chatIdRegex.test(telegramChatId)) {
      return res.status(400).json({ error: '無效的 Telegram Chat ID 格式' });
    }

    // 2. 防範 IDOR 越權修改：強制使用 JWT 解析出的伺服器端 req.user.id，而非由 body 傳入的 ID
    const userId = req.user.id; 

    // 3. 使用 Sequelize ORM 更新資料庫
    const user = await User.findByPk(userId);
    if (!user) {
      return res.status(404).json({ error: '找不到該使用者' });
    }

    user.telegram_chat_id = telegramChatId;
    await user.save();

    return res.status(200).json({ 
      message: 'Telegram 帳號綁定成功', 
      chatId: telegramChatId 
    });
  } catch (error) {
    console.error('綁定 Telegram 發生錯誤:', error);
    return res.status(500).json({ error: '伺服器內部錯誤' });
  }
});

module.exports = router;

