# ==========================================
# 專案名稱：Nginx 反向代理與 SSL 安全憑證配置範例
# 目的：配置 80/443 連接埠轉發，並處理 Let's Encrypt ACME 驗證
# ==========================================
server {
    listen 80;
    server_name water-monitor.lab.edu;

    # 1. 處理 Let's Encrypt / ACME 挑戰驗證 (HTTP-01 Challenge)
    location /.well-known/acme-challenge/ {
        root /var/www/letsencrypt;
        try_files $uri =404;
    }

    # 2. 自動將一般 HTTP 流量重導向至安全的 HTTPS
    location / {
        return 301 https://$host$request_uri;
    }
}

server {
    listen 443 ssl;
    server_name water-monitor.lab.edu;

    # 3. SSL 安全憑證路徑設定 (Let's Encrypt 產出)
    ssl_certificate /etc/letsencrypt/live/water-monitor.lab.edu/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/water-monitor.lab.edu/privkey.pem;
    ssl_protocols TLSv1.2 TLSv1.3;

    # 4. 反向代理轉發：將流量安全導向實驗室內網 API
    location / {
        proxy_pass http://10.8.0.5:3000; # 實驗室 VPN 內網 Node.js API 伺服器
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }
}
